import React from 'react';
import { Heartbeat, Newspaper, Lightning, Envelope } from '@phosphor-icons/react';
import { EfPanel } from '../ui/EfPanel';

export function DashboardAlerts({ injured, expiringContracts, avgEnergy, engine, setTab }) {
    if (injured.length === 0 && expiringContracts.length === 0 && avgEnergy >= 50 && (engine.transferOffers?.length ?? 0) === 0) {
        return null;
    }

    return (
        <div className="ef-dashboard-alerts">
            {injured.length > 0 && (
                <EfPanel padding="sm" className="ef-dashboard-alert ef-dashboard-alert--injury">
                    <Heartbeat color="var(--danger)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-dashboard-alert__text--danger">
                        {injured.length} LESIONADO{injured.length > 1 ? 'S' : ''}
                    </span>
                </EfPanel>
            )}
            {expiringContracts.length > 0 && (
                <EfPanel padding="sm" className="ef-dashboard-alert ef-dashboard-alert--contract">
                    <Newspaper color="var(--accent)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-dashboard-alert__text--secondary">
                        {expiringContracts.length} CONTRATO{expiringContracts.length > 1 ? 'S' : ''}
                    </span>
                </EfPanel>
            )}
            {avgEnergy < 50 && (
                <EfPanel padding="sm" className="ef-dashboard-alert ef-dashboard-alert--energy">
                    <Lightning color="var(--danger)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-dashboard-alert__text--danger">
                        CANSADO ({avgEnergy.toFixed(0)}%)
                    </span>
                </EfPanel>
            )}
            {(engine.transferOffers?.length ?? 0) > 0 && (
                <EfPanel padding="sm" className="ef-dashboard-alert ef-dashboard-alert--transfer ef-dashboard-alert--clickable" onClick={() => setTab('transfers')}>
                    <Envelope color="var(--info)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-dashboard-alert__text--info">
                        {(engine.transferOffers?.length ?? 0)} OFERTA{(engine.transferOffers?.length ?? 0) > 1 ? 'S' : ''}
                    </span>
                </EfPanel>
            )}
        </div>
    );
}

import React from 'react';
import { TrendUp, TrendDown, Wallet } from '@phosphor-icons/react';
import { EfPanel } from '../ui/EfPanel';

export function DashboardHeader({ pos, team, stats, boardStatus, engine }) {
    return (
        <EfPanel variant="hero" padding="lg" className="ef-dashboard-header">
            <div className="ef-dashboard-header__left">
                <div className="ef-dashboard-team-badge">
                    {pos}º • SÉRIE {['A','B','C','D'][team.division - 1]}
                </div>
                <h2 className="ef-dashboard-team-name">
                    {team.name}
                </h2>
                <span className="ef-dashboard-team-stats">
                    {stats.wins}V {stats.draws}E {stats.losses}D
                    {stats.streak > 0 ? (
                        <span className="ef-dashboard-team-stats__win">
                            <TrendUp weight="bold"/> {stats.streak}
                        </span>
                    ) : stats.streak < 0 ? (
                        <span className="ef-dashboard-team-stats__loss">
                            <TrendDown weight="bold"/> {Math.abs(stats.streak)}
                        </span>
                    ) : ''}
                </span>
            </div>
            <div className="ef-dashboard-header__right">
                <div className={`ef-dashboard-balance ${team.balance > 0 ? 'ef-dashboard-balance--positive' : 'ef-dashboard-balance--negative'}`}>
                    <Wallet weight="fill" className="ef-dashboard-balance__icon" />
                    R$ {(team.balance / 1000000).toFixed(1)}M
                </div>
                {boardStatus && (
                    <div className="ef-dashboard-board-status" title={`Diretoria: ${boardStatus.label} (${engine.board?.confidence ?? 60}%).`}>
                        <span>{boardStatus.emoji}</span> {boardStatus.label}
                    </div>
                )}
            </div>
        </EfPanel>
    );
}

import React from 'react';
import { SoccerBall } from '@phosphor-icons/react';
import { EfPanel } from '../ui/EfPanel';
import { EfButton } from '../ui/EfButton';

export function DashboardHeroMatch({ team, nextOpponentName, stadiumLabel, engine, setPacingQueue, changeView, forceUpdate }) {
    return (
        <EfPanel variant="hero" padding="lg" className="ef-dashboard-hero-match">
            <div className="ef-dashboard-hero-match__tag">PRÓXIMO JOGO</div>
            <div className="ef-dashboard-hero-match__body">
                <div className="ef-dashboard-hero-match__teams">
                    <div className="ef-dashboard-hero-match__team">
                        <div className="ef-dashboard-hero-match__crest ef-dashboard-hero-match__crest--home">
                            <span className="ef-dashboard-hero-match__crest-letter">{(team.name?.[0] || 'F').toUpperCase()}</span>
                        </div>
                        <p className="ef-dashboard-hero-match__team-name">{team.name?.toUpperCase()}</p>
                    </div>
                    <div className="ef-dashboard-hero-match__vs">VS</div>
                    <div className="ef-dashboard-hero-match__team">
                        <div className="ef-dashboard-hero-match__crest ef-dashboard-hero-match__crest--away">
                            <span className="ef-dashboard-hero-match__crest-letter">{(nextOpponentName[0] || '?').toUpperCase()}</span>
                        </div>
                        <p className="ef-dashboard-hero-match__team-name">{String(nextOpponentName).toUpperCase()}</p>
                    </div>
                </div>
                <div className="ef-dashboard-hero-match__meta">
                    <div className="ef-dashboard-hero-match__info-box">
                        <p className="ef-dashboard-hero-match__info-label">ESTÁDIO: {stadiumLabel}</p>
                        <p className="ef-dashboard-hero-match__info-value">FORMAÇÃO: {team.formation}</p>
                    </div>
                    <EfButton
                        variant="primary"
                        size="lg"
                        className="ef-dashboard-hero-match__cta"
                        onClick={() => {
                            const events = engine.getPacingEvents?.() || [];
                            if (events.length > 0) {
                                setPacingQueue(events);
                            } else {
                                engine.checkPressConference();
                                if (!engine.pressQuestion) changeView('match'); else forceUpdate();
                            }
                        }}
                    >
                        <SoccerBall weight="fill" /> ESCALAR E JOGAR
                    </EfButton>
                </div>
            </div>
        </EfPanel>
    );
}

import React from 'react';
import { WarningCircle, Brain, Lightning } from '@phosphor-icons/react';
import { EfPanel } from '../ui/EfPanel';

export function PlayerDashboardAlerts({ player }) {
    if (!player.isBenched && player.stress < 75 && player.energy >= 30) {
        return null;
    }

    return (
        <div className="ef-player-dashboard__alerts">
            {player.isBenched && (
                <EfPanel padding="sm" className="ef-player-dashboard__alert-panel">
                    <WarningCircle color="var(--color-danger)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-mono">VOCÊ ESTÁ NO BANCO!</span>
                </EfPanel>
            )}
            {player.stress >= 75 && (
                <EfPanel padding="sm" className="ef-player-dashboard__alert-panel">
                    <Brain color="var(--color-danger)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-mono">STRESS CRÍTICO ({player.stress}%)</span>
                </EfPanel>
            )}
            {player.energy < 30 && (
                <EfPanel padding="sm" className="ef-player-dashboard__alert-panel">
                    <Lightning color="var(--color-danger)" weight="fill" />
                    <span className="ef-dashboard-alert__text ef-mono">EXAUSTÃO ({player.energy}%)</span>
                </EfPanel>
            )}
        </div>
    );
}

